    onDataViewUserChildtap: function(dataview, location, eOpts) {
        // 1. Detectar si el toque fue en un botón de acción
            // Buscamos la clase '.action-btn' en el elemento tocado o sus padres
            var btn = location.event.getTarget('.action-btn');

            if (btn) {
                // 2. Extraer la acción y el registro
                var action = btn.getAttribute('data-action');
                //var record = location.record.data;
                //const data = record.getData ? record.getData() : record;
                var record = location.record;
                var data   = record ? (record.getData ? record.getData() : record) : null;


                // Detenemos la propagación para que no seleccione la fila al tocar el botón
                location.event.stopEvent();

                // 3. Switch Maestro de Acciones
                switch (action) {
                    case 'view':
                        // Obtener el record
                        //const data = record.getData ? record.getData() : record;
                        const canNavigate = (data.node_type === 'collection' || data.node_type === 'resource'); //&& data.has_children;

                        // Sino se puede navergar lanzar una alerta
                        if (!canNavigate) {

                            Ext.toast({
                                timeout: 2500,
                                cls: 'toast-clean',
                                message: `
                                    <div style="
                                    background:#FFF3CD;
                                    color:#856404;
                                    padding:10px 12px;
                                    border-radius:14px;
                                    font-weight:600;
                                    ">
                                    ⚠️ Esta pestaña no tiene contenido navegable
                                    </div>
                                    `
                            });
                            return;
                        }

                        // Guardar el record en el formView
                        var form = Ext.getCmp("formView");
                        form.nodeRecord = record;

                        // Lanzar la función para pintar la información
                        //this.navigateToView('');
                        this.showFormView(record);
                        console.log('treeNav',appLocal.getCurrentBreadcrumb());
                        break;

                    case 'edit':
                        console.warn('Tap: edit', record);
                        this.showForm('edit', record);

                        break;

                    case 'delete':
                        // Obtener el formulario
                        var contMain = Ext.getCmp('contMain');
                        var form = Ext.getCmp('formNode');

                        if (!form) {
                            Ext.toast('No se encontró el formulario.');
                            return;
                        }

                        // Obtener el record del node
                        var rec = form.nodeRecord || null;

                        var dataRec = rec ? (rec.getData ? rec.getData() : rec) : null;
                        var nodeId  = data.id ? data.id : null;
                        var text    = data.text ? data.text : null;

                        if (!nodeId) {
                            Ext.toast('No se encontró el ID del nodo a eliminar.');
                            return;
                        }

                        if(data.has_children){
                            //jsDam.toast({ type:'error', title:'Error', message: 'Las colecciones del sistema no se pueden eliminar.' });
                            Ext.toast('No se puede eliminar, tiene hijos.');
                            return;
                        }

                        if(data.action && data.action === 'open_app'){
                            //jsDam.toast({ type:'error', title:'Error', message: 'Las colecciones del sistema no se pueden eliminar.' });
                            Ext.toast('Las colecciones del sistema no se pueden eliminar.');
                            return;
                        }

                        Ext.Msg.show({
                            title: 'Eliminar Registro',
                            message: '¿Realmente deseas eliminar este registro? Esta acción no se puede deshacer.',
                            width: 300, // Opcional
                            closable: false,
                            icon: Ext.Msg.QUESTION,
                            buttons: [
                                {
                                    text: 'No',
                                    itemId: 'no'
                                },
                                {
                                    text: 'Sí, borrar',
                                    itemId: 'yes',
                                    ui: 'action-decline'
                                }
                            ],
                            fn: function (buttonId) {
                                if (buttonId === 'yes') {

                                    appLocal.deleteNode(nodeId);

                                    console.log('Registro eliminado');
                                }
                            }
                        });
                        break;

                    default:
                        console.log('Evento no definido');
                }
            }
    },

